#include <stdio.h>
#include <stdlib.h>

static inline long long comb3(long long x) {
    if (x < 3) return 0;
    return x * (x - 1) * (x - 2) / 6;
}
static inline long long comb2(long long x) {
    if (x < 2) return 0;
    return x * (x - 1) / 2;
}

int main() {
    int T; if (scanf("%d", &T)!=1) return 0;
    while (T--) {
        int N, Q; scanf("%d %d", &N, &Q);
        int *oddPref = (int*)calloc(N+1, sizeof(int));
        for (int i = 1; i <= N; ++i) {
            long long val; scanf("%lld", &val);
            oddPref[i] = oddPref[i-1] + (val & 1LL);
        }
        while (Q--) {
            int L, R; scanf("%d %d", &L, &R);
            long long odd = oddPref[R] - oddPref[L-1];
            long long len = R - L + 1;
            long long even = len - odd;
            long long ans = comb3(even) + comb2(odd) * even;
            printf("%lld\n", ans);
        }
        free(oddPref);
    }
    return 0;
}

