import java.io.*;
import java.util.*;

public class Main {
    private static long C3(long x){ return x<3?0:x*(x-1)*(x-2)/6; }
    private static long C2(long x){ return x<2?0:x*(x-1)/2; }
    public static void main(String[] args) throws Exception {
        FastScanner fs = new FastScanner(System.in);
        int T = fs.nextInt();
        StringBuilder out = new StringBuilder();
        while (T-- > 0) {
            int N = fs.nextInt();
            int Q = fs.nextInt();
            int[] pref = new int[N+1];
            for (int i = 1; i <= N; i++) {
                long val = fs.nextLong();
                pref[i] = pref[i-1] + ((val & 1L) == 1L ? 1 : 0);
            }
            for (int q = 0; q < Q; q++) {
                int L = fs.nextInt();
                int R = fs.nextInt();
                long odd = pref[R] - pref[L-1];
                long len = R - L + 1L;
                long even = len - odd;
                long ans = C3(even) + C2(odd) * even;
                out.append(ans).append('\n');
            }
        }
        System.out.print(out.toString());
    }

    // Fast scanner based on BufferedInputStream
    static class FastScanner {
        private final byte[] buffer = new byte[1 << 16];
        private int ptr = 0, len = 0;
        private final InputStream in;
        FastScanner(InputStream in){ this.in = in; }
        private int readByte() throws IOException {
            if (ptr >= len) {
                len = in.read(buffer);
                ptr = 0;
                if (len <= 0) return -1;
            }
            return buffer[ptr++];
        }
        long nextLong() throws IOException {
            int c; do { c = readByte(); } while (c <= ' ');
            boolean neg = false;
            if (c == '-') { neg = true; c = readByte(); }
            long val = 0;
            while (c > ' ') {
                val = val * 10 + (c - '0');
                c = readByte();
            }
            return neg ? -val : val;
        }
        int nextInt() throws IOException { return (int) nextLong(); }
    }
}

